// === DISPATCH: prepare les articles + dossier de sortie unique ===
const input = $input.first().json;
const body = input.body || input;
const mode = body.mode || 'screening';
const articles = body.articles || [];
const question = body.question || '';
const criteria = body.criteria || '';
const extractFields = body.extract_fields || null;

console.log('Module: ' + mode + ' avec ' + articles.length + ' articles');

if (articles.length === 0) {
  return [{ json: { error: 'Aucun article fourni', mode } }];
}

// Generer un dossier de sortie unique : /desktop/ultralab-module-<mode>-<YYYYMMDD-HHMM>/
const now = new Date();
const pad = n => String(n).padStart(2, '0');
const timestamp = now.getFullYear() + pad(now.getMonth()+1) + pad(now.getDate()) + '-' + pad(now.getHours()) + pad(now.getMinutes());
const folderName = 'ultralab-module-' + mode + '-' + timestamp;
// D.8 custom output_folder : si l'user a choisi un dossier custom via UI, on l'utilise.
// Sinon default : /desktop/ultralab-module-<mode>-<timestamp>/
const userOutputFolder = (body.output_folder && typeof body.output_folder === 'string') ? body.output_folder.trim().replace(/\/+$/, '') : '';
let outputFolder;
if (userOutputFolder && userOutputFolder.startsWith('/desktop')) {
  // Path Docker valide (commence par /desktop) -> on append le sub-folder mode-timestamp
  outputFolder = userOutputFolder + '/' + folderName;
} else {
  outputFolder = '/desktop/' + folderName;
}
console.log('Dossier de sortie : ' + outputFolder);

// Enrichir le premier article avec question/criteres + output_folder partout
const enriched = articles.map((a, i) => {
  const article = { ...a, output_folder: outputFolder, _module_mode: mode, _folder_name: folderName };
  if (i === 0) {
    article.question = question;
    article.criteria = criteria;
    article.prefilter_enabled = false;
    if (extractFields) article.extract_fields = extractFields;
    // Skip flags : on saute les autres etapes (juste le module demande)
    article.skip_ranking = mode !== 'ranking';
    article.skip_clustering = mode !== 'clustering';
    article.skip_screening = mode !== 'screening';
    article.skip_pdf = mode !== 'pdf-fetch';
  }
  // Pour le PDF fetch, marquer tous comme Include si pas de screening_decision
  if (mode === 'pdf-fetch' && !article.screening_decision) {
    article.screening_decision = 'Include';
  }
  return { json: article };
});

return enriched;

// === ASSEMBLE + EXPORT MODULE RESULTS ===
const XLSX = require('xlsx');
const PROXY = 'http://host.docker.internal:3456';
const items = $input.all();
const articles = items.map(i => i.json);
const mode = (articles[0] && articles[0]._module_mode) || 'unknown';
const outputFolder = (articles[0] && articles[0].output_folder) || '/desktop/ultralab-module-output';
const folderName = (articles[0] && articles[0]._folder_name) || 'ultralab-module-output';

let stats = { total: articles.length };

// === STATS PAR MODULE ===
if (mode === 'screening') {
  stats.include = articles.filter(a => a.screening_decision === 'Include').length;
  stats.maybe = articles.filter(a => a.screening_decision === 'Maybe').length;
  stats.exclude = articles.filter(a => a.screening_decision === 'Exclude').length;
} else if (mode === 'ranking') {
  const scores = articles.map(a => a.score || 0);
  stats.avg_score = scores.length > 0 ? Math.round(scores.reduce((a,b) => a+b, 0) / scores.length) : 0;
  stats.high_score = scores.filter(s => s >= 70).length;
  stats.med_score = scores.filter(s => s >= 40 && s < 70).length;
  stats.low_score = scores.filter(s => s < 40).length;
} else if (mode === 'clustering') {
  const labels = new Set(articles.map(a => a.cluster_label).filter(Boolean));
  stats.clusters = labels.size;
  stats.cluster_list = [...labels];
} else if (mode === 'pdf-fetch') {
  stats.downloaded = articles.filter(a => a.pdf_local).length;
  stats.failed = articles.filter(a => a.pdf_url && !a.pdf_local).length;
  stats.no_doi = articles.filter(a => !a.doi).length;
} else if (mode === 'extraction') {
  stats.extracted_ok = articles.filter(a => a._extract_status === 'ok').length;
  stats.extracted_failed = articles.filter(a => a._extract_status && a._extract_status !== 'ok').length;
  stats.with_pdf = articles.filter(a => a._extract_source && a._extract_source.indexOf('PDF') === 0).length;
  stats.abstract_only = articles.filter(a => a._extract_source && a._extract_source.indexOf('abstract') === 0).length;
} else if (mode === 'deduplicate') {
  stats.before = (articles[0] && articles[0]._total_before_dedup) || articles.length;
  stats.after = articles.length;
  stats.duplicates_removed = (articles[0] && articles[0]._duplicates_removed) || 0;
  stats.dedup_rate_pct = stats.before > 0 ? Math.round(stats.duplicates_removed / stats.before * 100) : 0;
}

// === GENERER LE FICHIER RIS ===
function buildRIS(articles, mode) {
  let ris = '';
  for (const a of articles) {
    const title = (a.title || '').replace(/\n/g, ' ');
    const authors = Array.isArray(a.authors) ? a.authors : [];
    ris += 'TY  - JOUR\n';
    ris += 'TI  - ' + title + '\n';
    authors.forEach(au => { ris += 'AU  - ' + au + '\n'; });
    if (a.year) ris += 'PY  - ' + a.year + '\n';
    if (a.journal) ris += 'JO  - ' + (a.journal || '').replace(/\n/g, ' ') + '\n';
    if (a.doi) ris += 'DO  - ' + a.doi + '\n';
    if (a.abstract) ris += 'AB  - ' + (a.abstract || '').replace(/\n/g, ' ').substring(0, 2000) + '\n';
    // Annotations selon le mode
    if (mode === 'screening' && a.screening_decision) {
      ris += 'N1  - screening:' + a.screening_decision + (a.screening_reason ? ' - ' + a.screening_reason : '') + '\n';
    }
    if (mode === 'ranking' && a.score !== undefined) {
      ris += 'N1  - relevance_score:' + a.score + (a.score_reason ? ' - ' + a.score_reason : '') + '\n';
    }
    if (mode === 'clustering' && a.cluster_label) {
      ris += 'N1  - cluster:' + a.cluster_label + '\n';
    }
    if (mode === 'extraction' && a._extracted) {
      for (const k of Object.keys(a._extracted)) {
        const v = String(a._extracted[k] || '').replace(/\n/g, ' ').substring(0, 500);
        if (v) ris += 'N1  - ' + k + ':' + v + '\n';
      }
    }
    if (a.url || a.pdf_url) ris += 'UR  - ' + (a.pdf_url || a.url) + '\n';
    ris += 'ER  - \n\n';
  }
  return ris;
}

// === GENERER L'EXCEL ADAPTE AU MODULE ===
function buildXLSX(articles, mode) {
  // === HARDENING XLSX : tronque cellules a 32700 chars max + retire chars de controle ===
  // xlsx (SheetJS) plante avec "Text length must not exceed 32767 characters" sur tout
  // contenu trop long. Limite officielle Excel. On tronque defensivement a 32700.
  // Egalement : Excel n'accepte pas certains caracteres de controle (< 0x20 sauf \t \n \r).
  function safeCell(v) {
    if (v === null || v === undefined) return '';
    if (typeof v === 'number' || typeof v === 'boolean') return v;
    let s = (typeof v === 'string') ? v : (typeof v === 'object' ? JSON.stringify(v) : String(v));
    // Retire caracteres de controle (sauf tab, LF, CR)
    s = s.replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, ' ');
    if (s.length > 32700) {
      s = s.substring(0, 32700) + ' [tronque a 32700 chars]';
    }
    return s;
  }

  const wb = XLSX.utils.book_new();
  let headers, rows;

  if (mode === 'screening') {
    headers = ['Titre', 'Auteurs', 'Annee', 'Journal', 'DOI', 'Decision', 'Justification', 'Abstract'];
    const order = { 'Include': 0, 'Maybe': 1, 'Exclude': 2 };
    const sorted = [...articles].sort((a,b) => (order[a.screening_decision]||1) - (order[b.screening_decision]||1));
    rows = sorted.map(a => [a.title||'', (a.authors||[]).join('; '), a.year||'', a.journal||'', a.doi||'', a.screening_decision||'Maybe', a.screening_reason||'', (a.abstract||'').substring(0,1000)]);
  } else if (mode === 'ranking') {
    headers = ['Score', 'Titre', 'Auteurs', 'Annee', 'Journal', 'DOI', 'Topic', 'Population', 'Methodology', 'Context', 'Justification', 'Abstract'];
    const sorted = [...articles].sort((a,b) => (b.score||0) - (a.score||0));
    rows = sorted.map(a => {
      const bd = a.score_breakdown || {};
      return [a.score||0, a.title||'', (a.authors||[]).join('; '), a.year||'', a.journal||'', a.doi||'', bd.topic||'', bd.population||'', bd.methodology||'', bd.context||'', a.score_reason||'', (a.abstract||'').substring(0,1000)];
    });
  } else if (mode === 'clustering') {
    headers = ['Cluster', 'Titre', 'Auteurs', 'Annee', 'Journal', 'DOI', 'Abstract'];
    const sorted = [...articles].sort((a,b) => (a.cluster_label||'').localeCompare(b.cluster_label||''));
    rows = sorted.map(a => [a.cluster_label||'Unclustered', a.title||'', (a.authors||[]).join('; '), a.year||'', a.journal||'', a.doi||'', (a.abstract||'').substring(0,1000)]);
  } else if (mode === 'pdf-fetch') {
    headers = ['Titre', 'Auteurs', 'Annee', 'DOI', 'PDF telecharge', 'Source PDF', 'Chemin local', 'URL'];
    rows = articles.map(a => [a.title||'', (a.authors||[]).join('; '), a.year||'', a.doi||'', a.pdf_local ? 'Oui' : 'Non', a.pdf_source||'', a.pdf_local||'', a.pdf_url||a.url||'']);
  } else if (mode === 'extraction') {
    // Recuperer dynamiquement les champs extraits du premier article
    const extractedKeys = new Set();
    articles.forEach(a => { if (a._extracted) Object.keys(a._extracted).forEach(k => extractedKeys.add(k)); });
    const fieldNames = [...extractedKeys];
    headers = ['Titre', 'Auteurs', 'Annee', 'DOI', 'Source extraction', 'Statut'].concat(fieldNames);
    rows = articles.map(a => {
      const ext = a._extracted || {};
      return [a.title||'', (a.authors||[]).join('; '), a.year||'', a.doi||'', a._extract_source||'', a._extract_status||'']
        .concat(fieldNames.map(f => ext[f] !== undefined ? String(ext[f]) : ''));
    });
  } else if (mode === 'deduplicate') {
    headers = ['Titre', 'Auteurs', 'Annee', 'Journal', 'DOI', 'Source', 'Cle dedup'];
    rows = articles.map(a => [a.title||'', (a.authors||[]).join('; '), a.year||'', a.journal||'', a.doi||'', a.source||'', a._deduplication_key||'']);
  } else {
    headers = ['Titre', 'Auteurs', 'Annee', 'DOI'];
    rows = articles.map(a => [a.title||'', (a.authors||[]).join('; '), a.year||'', a.doi||'']);
  }

  // Hardening : applique safeCell sur chaque cellule (anti crash xlsx 32767 chars)
  rows = rows.map(r => Array.isArray(r) ? r.map(safeCell) : r);
  headers = headers.map(safeCell);
  const wsData = [headers, ...rows];
  const ws = XLSX.utils.aoa_to_sheet(wsData);
  ws['!cols'] = headers.map(h => ({ wch: h.length < 8 ? 12 : (h === 'Titre' ? 50 : (h === 'Abstract' ? 60 : 25)) }));
  ws['!autofilter'] = { ref: XLSX.utils.encode_range({ s: { r: 0, c: 0 }, e: { r: wsData.length - 1, c: headers.length - 1 } }) };

  // Couleurs pour la colonne Decision (screening)
  if (mode === 'screening') {
    for (let r = 1; r < wsData.length; r++) {
      const cell = ws[XLSX.utils.encode_cell({ r, c: 5 })];
      if (cell) {
        const d = wsData[r][5];
        const bg = d === 'Include' ? '00B050' : (d === 'Exclude' ? 'FF0000' : 'FFA500');
        cell.s = { fill: { fgColor: { rgb: bg } }, font: { color: { rgb: 'FFFFFF' }, bold: true } };
      }
    }
  }
  // Style header
  for (let c = 0; c < headers.length; c++) {
    const cell = ws[XLSX.utils.encode_cell({ r: 0, c })];
    if (cell) cell.s = { fill: { fgColor: { rgb: '4472C4' } }, font: { color: { rgb: 'FFFFFF' }, bold: true } };
  }

  XLSX.utils.book_append_sheet(wb, ws, 'Resultats');

  // Sheet stats
  const statsRows = [['Statistiques module ' + mode], [], ['Total articles', articles.length]];
  for (const k of Object.keys(stats)) {
    if (k !== 'total' && k !== 'cluster_list') statsRows.push([k, stats[k]]);
  }
  const wsS = XLSX.utils.aoa_to_sheet(statsRows);
  wsS['!cols'] = [{ wch: 30 }, { wch: 15 }];
  XLSX.utils.book_append_sheet(wb, wsS, 'Statistiques');
  // D.6 phase 2 : feuille "Doublons" pour mode deduplicate
  if (mode === 'deduplicate') {
    const firstArt = articles[0] || {};
    const dedupReport = firstArt._dedup_report || null;
    if (dedupReport && Array.isArray(dedupReport.duplicates_detail) && dedupReport.duplicates_detail.length > 0) {
      const dupHeaders = ['Strategie', 'Confidence', 'Titre doublon', 'Titre master', 'Cle de match'];
      const dupRows = dedupReport.duplicates_detail.map(d => [
        d.strategy || '',
        d.confidence || '',
        d.duplicate_title || '',
        d.master_title || '',
        d.key_excerpt || ''
      ]);
      const dupData = [dupHeaders, ...dupRows].map(r => Array.isArray(r) ? r.map(safeCell) : r);
      const wsD = XLSX.utils.aoa_to_sheet(dupData);
      wsD['!cols'] = [{ wch: 18 }, { wch: 12 }, { wch: 50 }, { wch: 50 }, { wch: 30 }];
      if (dupData.length > 1) {
        wsD['!autofilter'] = { ref: XLSX.utils.encode_range({ s: { r: 0, c: 0 }, e: { r: dupData.length - 1, c: dupHeaders.length - 1 } }) };
      }
      XLSX.utils.book_append_sheet(wb, wsD, 'Doublons');
    }
  }


  return Buffer.from(XLSX.write(wb, { type: 'buffer', bookType: 'xlsx' })).toString('base64');
}

// === ECRIRE LES FICHIERS VIA LE PROXY ===
async function saveFile(savePath, content, isBase64) {
  try {
    const body = isBase64 ? { save_to: savePath, content_base64: content } : { save_to: savePath, content };
    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: PROXY + '/save',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body),
      timeout: 60000
    });
    return resp && resp.success;
  } catch (e) {
    console.log('Save error: ' + e.message);
    return false;
  }
}

// === D.6 phase 2 : Generer le fichier .nbib (format MEDLINE) des articles uniques ===
function buildNbib(articles) {
  function fmt(tag, value) {
    if (!value && value !== 0) return '';
    const v = String(value).replace(/\r/g, '').replace(/\n/g, ' ').trim();
    if (!v) return '';
    return tag.padEnd(4) + '- ' + v + '\n';
  }
  function toEntry(a) {
    let out = '';
    if (a.pmid) out += fmt('PMID', a.pmid);
    out += fmt('OWN', 'NLM');
    out += fmt('STAT', 'MEDLINE');
    out += fmt('PT', 'Journal Article');
    out += fmt('TI', a.title);
    if (Array.isArray(a.authors)) {
      for (const au of a.authors) {
        if (!au) continue;
        out += fmt('FAU', au);
        const parts = au.trim().split(/\s+/);
        if (parts.length >= 2) {
          const last = parts[parts.length - 1];
          const initials = parts.slice(0, -1).map(p => p.charAt(0).toUpperCase()).join('');
          out += fmt('AU', last + ' ' + initials);
        } else {
          out += fmt('AU', au);
        }
      }
    }
    if (a.journal) { out += fmt('JT', a.journal); out += fmt('TA', a.journal); }
    if (a.volume) out += fmt('VI', a.volume);
    if (a.issue) out += fmt('IP', a.issue);
    if (a.pages) out += fmt('PG', a.pages);
    if (a.year) out += fmt('DP', a.year);
    if (a.abstract) out += fmt('AB', a.abstract);
    if (a.doi) {
      out += fmt('AID', a.doi + ' [doi]');
      out += fmt('LID', a.doi + ' [doi]');
    }
    if (a._source) out += fmt('SO', '[source:' + a._source + ']');
    return out + '\n';
  }
  return articles.map(toEntry).join('');
}

// === GENERER RAPPORT MARKDOWN LISIBLE ===
function buildReport(articles, mode, stats, folderName) {
  const now = new Date().toLocaleString('fr-FR');
  let r = '# UltraLab - Rapport module ' + mode + '\n\n';
  r += '**Date** : ' + now + '\n';
  r += '**Dossier** : `' + folderName + '`\n';
  r += '**Articles traites** : ' + articles.length + '\n\n';
  r += '---\n\n## Statistiques\n\n';
  for (const k of Object.keys(stats)) {
    if (k === 'cluster_list') continue;
    r += '- **' + k + '** : ' + stats[k] + '\n';
  }
  r += '\n---\n\n## Resume par module\n\n';

  if (mode === 'screening') {
    const inc = articles.filter(a => a.screening_decision === 'Include').slice(0, 10);
    const may = articles.filter(a => a.screening_decision === 'Maybe').slice(0, 5);
    r += '### Top 10 articles inclus\n\n';
    inc.forEach((a, i) => { r += (i+1) + '. **' + (a.title || '?').substring(0, 100) + '** _(' + (a.year || 'n.d.') + ')_\n   Raison : ' + (a.screening_reason || '').substring(0, 150) + '\n'; });
    r += '\n### Top 5 "Maybe" a re-examiner manuellement\n\n';
    may.forEach((a, i) => { r += (i+1) + '. ' + (a.title || '?').substring(0, 100) + ' - ' + (a.screening_reason || '').substring(0, 100) + '\n'; });
  } else if (mode === 'ranking') {
    const top = [...articles].sort((a,b) => (b.score||0) - (a.score||0)).slice(0, 10);
    r += '### Top 10 articles par pertinence\n\n';
    top.forEach((a, i) => { r += (i+1) + '. **[' + (a.score||0) + '/100]** ' + (a.title || '?').substring(0, 100) + '\n   ' + (a.score_reason || '').substring(0, 150) + '\n'; });
  } else if (mode === 'clustering') {
    const byCluster = {};
    articles.forEach(a => { const c = a.cluster_label || 'Unclustered'; (byCluster[c] = byCluster[c] || []).push(a); });
    r += '### Clusters identifies\n\n';
    for (const c of Object.keys(byCluster)) {
      r += '- **' + c + '** : ' + byCluster[c].length + ' articles\n';
      byCluster[c].slice(0, 3).forEach(a => { r += '  - ' + (a.title || '?').substring(0, 90) + '\n'; });
    }
  } else if (mode === 'pdf-fetch') {
    const ok = articles.filter(a => a.pdf_local).slice(0, 10);
    const ko = articles.filter(a => !a.pdf_local && !!a.doi).slice(0, 10);
    r += '### Top 10 PDFs telecharges\n\n';
    ok.forEach((a, i) => { r += (i+1) + '. ' + (a.title || '?').substring(0, 100) + ' [' + (a.pdf_source || '') + ']\n'; });
    r += '\n### Top 10 echecs (DOI sans PDF)\n\n';
    ko.forEach((a, i) => { r += (i+1) + '. ' + (a.title || '?').substring(0, 100) + ' - DOI : ' + a.doi + '\n'; });
  } else if (mode === 'extraction') {
    const ok = articles.filter(a => a._extract_status === 'ok').slice(0, 5);
    r += '### 5 premiers articles avec extraction reussie\n\n';
    ok.forEach((a, i) => {
      r += (i+1) + '. **' + (a.title || '?').substring(0, 100) + '**\n';
      const ext = a._extracted || {};
      for (const k of Object.keys(ext).slice(0, 5)) {
        r += '   - _' + k + '_ : ' + String(ext[k]).substring(0, 200) + '\n';
      }
    });
  } else if (mode === 'deduplicate') {
    r += '### Statistiques de deduplication\n\n';
    r += '- Articles initiaux : ' + (stats.before || 0) + '\n';
    r += '- Articles uniques apres dedup : ' + (stats.after || 0) + '\n';
    r += '- Doublons supprimes : ' + (stats.duplicates_removed || 0);
    r += ' (taux : ' + (stats.dedup_rate_pct || 0) + '%)\n\n';

    // D.6 phase 2 : exploite _dedup_report injecte par Dedup v2
    const firstArt = articles[0] || {};
    const dedupReport = firstArt._dedup_report || null;
    if (dedupReport) {
      r += '### Repartition par strategie de detection\n\n';
      const strat = dedupReport.strategies || {};
      r += '- DOI identique (high confidence) : ' + (strat.doi || 0) + '\n';
      r += '- Titre + annee + 1er auteur (medium confidence) : ' + (strat['title+year+author'] || 0) + '\n';
      r += '- Titre normalise seul (low confidence, a re-verifier) : ' + (strat['title-only'] || 0) + '\n\n';

      const bySrc = dedupReport.by_source || {};
      if (Object.keys(bySrc).length > 0) {
        r += '### Repartition des uniques par source\n\n';
        for (const k of Object.keys(bySrc)) {
          r += '- ' + k + ' : ' + bySrc[k] + ' articles\n';
        }
        r += '\n';
      }

      const dups = dedupReport.duplicates_detail || [];
      if (dups.length > 0) {
        r += '### Echantillon des 10 premiers doublons detectes\n\n';
        dups.slice(0, 10).forEach((d, i) => {
          r += (i + 1) + '. **Strategie : ' + d.strategy + '** (' + d.confidence + ')\n';
          r += '   - Doublon : ' + (d.duplicate_title || '?').substring(0, 100) + '\n';
          r += '   - Master  : ' + (d.master_title || '?').substring(0, 100) + '\n';
          if (d.key_excerpt) r += '   - Cle    : ' + d.key_excerpt + '\n';
        });
        if (dups.length > 10) r += '\n_... et ' + (dups.length - 10) + ' autres doublons (voir Excel sheet "Doublons" pour la liste complete)_\n';
        r += '\n';
      }
    }

    r += '### Echantillon des 10 premiers articles uniques\n\n';
    articles.slice(0, 10).forEach((a, i) => { r += (i+1) + '. ' + (a.title || '?').substring(0, 100) + '\n'; });
  }

  r += '\n---\n\n_Genere par UltraLab - https://github.com/yourrepo/ultralab_\n';
  return r;
}

const risContent = buildRIS(articles, mode);
const xlsxBase64 = buildXLSX(articles, mode);
// Pour mode extraction : ajouter dans le summary la 1ere reponse LLM si echec
const summaryObj = { mode, stats, articles_count: articles.length, generated_at: new Date().toISOString() };
if (mode === 'extraction') {
  const ok = articles.filter(a => a._extract_status === 'ok');
  const failed = articles.filter(a => a._extract_status && a._extract_status !== 'ok');
  if (failed.length > 0) {
    const status_breakdown = {};
    articles.forEach(a => {
      const s = a._extract_status || 'unknown';
      status_breakdown[s] = (status_breakdown[s] || 0) + 1;
    });
    const samples = failed.slice(0, 5).map(a => ({
      title: (a.title || '').substring(0, 80),
      doi: a.doi || '',
      status: a._extract_status,
      source: a._extract_source,
      pdf_local: a.pdf_local || null,
      llm_raw_first_500: a._debug_llm_raw || null,
      llm_keys: a._debug_llm_keys || null
    }));
    const ok_samples = ok.slice(0, 2).map(a => ({
      title: (a.title || '').substring(0, 80),
      source: a._extract_source,
      llm_raw_first_500: a._debug_llm_raw || null
    }));
    summaryObj._diagnostic = {
      issue: ok.length === 0 ? 'AUCUNE extraction reussie' : (ok.length + ' OK / ' + failed.length + ' echecs'),
      ok_count: ok.length,
      failed_count: failed.length,
      status_breakdown: status_breakdown,
      failed_samples: samples,
      ok_samples: ok_samples,
      causes_probables: [
        'parse_error : le LLM repond mais pas en JSON valide (souvent du au prompt tronque par num_ctx)',
        'llm_error : Ollama renvoie une erreur (OOM, modele decharge, timeout)',
        'no_response : Ollama coupe la connexion en streaming sans donner de reponse',
        'no_text_available : ni PDF ni abstract exploitables',
        'Pistes : augmenter num_ctx (8192), reduire la taille du prompt, ajouter format:json dans le payload Ollama'
      ]
    };
  }
}
const summary = JSON.stringify(summaryObj, null, 2);
const report = buildReport(articles, mode, stats, folderName);

// D.6 phase 2 : pour mode deduplicate, generer aussi un .nbib des articles uniques
let nbibOk = null;
if (mode === 'deduplicate') {
  const nbibContent = buildNbib(articles);
  const nbibPath = outputFolder + '/results-deduplicate.nbib';
  nbibOk = await saveFile.call(this, nbibPath, nbibContent, false);
  console.log('  + Fichier .nbib (articles uniques) : ' + nbibOk);
}
const risPath = outputFolder + '/results-' + mode + '.ris';
const xlsxPath = outputFolder + '/results-' + mode + '.xlsx';
const summaryPath = outputFolder + '/summary.json';
const reportPath = outputFolder + '/report.md';

const risOk = await saveFile.call(this, risPath, risContent, false);
const xlsxOk = await saveFile.call(this, xlsxPath, xlsxBase64, true);
const sumOk = await saveFile.call(this, summaryPath, summary, false);
const repOk = await saveFile.call(this, reportPath, report, false);

console.log('=== Module ' + mode + ' termine ===');
console.log('Articles: ' + articles.length);
console.log('Stats: ' + JSON.stringify(stats));
console.log('Fichiers : RIS=' + risOk + ' XLSX=' + xlsxOk + ' summary=' + sumOk + ' report=' + repOk);
console.log('Dossier  : ' + outputFolder);

return [{ json: {
  success: true,
  mode,
  stats,
  output_folder: outputFolder,
  folder_name: folderName,
  files: {
    ris: risOk ? 'results-' + mode + '.ris' : null,
    xlsx: xlsxOk ? 'results-' + mode + '.xlsx' : null,
    summary: sumOk ? 'summary.json' : null,
    report: repOk ? 'report.md' : null,
    nbib: (mode === 'deduplicate' && nbibOk) ? 'results-deduplicate.nbib' : null
  },
  articles_count: articles.length
}}];

// === RESPOND IMMEDIATELY (async webhook pattern) ===
// Envoie une reponse rapide au browser pour qu'il puisse fermer la connexion HTTP
// et basculer sur le polling. Le workflow continue en parallele.
const input = $input.first().json;
const body = input.body || input;
const mode = body.mode || 'screening';
const articlesCount = (body.articles || []).length;
const now = new Date();
const pad = n => String(n).padStart(2, '0');
const timestamp = now.getFullYear() + pad(now.getMonth()+1) + pad(now.getDate()) + '-' + pad(now.getHours()) + pad(now.getMinutes());
const expectedFolder = '/desktop/ultralab-module-' + mode + '-' + timestamp;
return [{
  json: {
    started: true,
    async: true,
    mode: mode,
    articles_count: articlesCount,
    expected_folder: expectedFolder,
    started_at: now.toISOString(),
    message: 'Workflow demarre en background sur n8n. Le browser doit poller /api/last-result pour recuperer le resultat final.'
  }
}];
